import Link from "next/link";

// assets
import {
  Dribbble,
  Facebook,
  Globe,
  Instagram,
  Slack,
  Twitter,
} from "lucide-react";

const brandLogo = "https://cdn.uiable.com/logo-dark.svg";

// constants
const socialLinks = [
  { icon: Slack, href: "#" },
  { icon: Twitter, href: "#" },
  { icon: Facebook, href: "#" },
  { icon: Dribbble, href: "#" },
  { icon: Globe, href: "#" },
  { icon: Instagram, href: "#" },
];

//  ------------------------------ | FOOTER - 7 | ------------------------------  //

export default function Footer7() {
  return (
    <footer className="py-16 md:py-20">
      <div className="container mx-auto px-4">
        <div className="grid grid-cols-12">
          <div className="col-span-12 flex flex-col items-center text-center gap-6">
            {/* Logo */}
            <img src={brandLogo} alt="Logo" />
            {/* Description */}
            <p className="text-muted-foreground max-w-md">
              At half-past eight the door opened, the policeman appeared.
            </p>

            {/* Social Icons */}
            <div className="flex items-center gap-6 mt-2">
              {socialLinks.map((item, index) => (
                <Link key={index} href={item.href} className="text-primary">
                  <item.icon size={22} strokeWidth={1.5} />
                </Link>
              ))}
            </div>
          </div>
        </div>
      </div>
    </footer>
  );
}
